<?phpnamespace App\Models;use Illuminate\Database\Eloquent\Model;class Etudiants extends Model{    protected $fillable = [        'nom',        'prenom',        'sexe',        'dateNaissance',        'lieuNaissance',        'adresse',        'nomPere',        'nomMere',        'telephonePere',        'telephoneMere',        'prenomMere',        'prenomPere',        'nomTuteur',        'prenomTuteur',        'telephoneTuteur',        'matricule',        'ecole',        'enfantProf',        'photo',        'ac_id',        'quit',        'quit_at',        'fired',        'fired_at',        'quit_motif',        'fired_motif'    ];    public function sousetudiants() {        return $this->hasMany(Sousetudiants::class, 'et_id', 'id');    }    public function scopeSexe($query, $sexe){        if($sexe == '0'){            return $query;        }else{            return $query->where('sexe', $sexe=='Homme'?1:0);        }    }    public function scopeYear($query, $annee){        if($annee == 0){            return $query;        }else{            return $query->Where('ac_id', $annee);        }    }    public function scopeYearNote($query, $annee){        if($annee == 0){            return $query;        }else{            return $query->whereHas('sousetudiants', function($q) use($annee){                $q->where('ac_id', $annee);            });        }    }    public function scopeClasse($query, $classe){        if($classe == 0){            return $query;        }else{            return $query->whereHas('sousetudiants', function($q) use ($classe){                $q->where('cl_id', $classe);            });        }    }    public function scopeLevel($query, $level){        if($level == 0){            return $query;        }else{            return $query->whereHas('sousetudiants', function($q) use ($level){                $q->whereHas('classe', function($q) use($level){                    $q->where('niveau', $level);                });            });        }    }    public function scopeSalle($query, $salle){        if($salle == 0){            return $query;        }else{            return $query->whereHas('sousetudiants', function($q) use ($salle){                $q->where('sa_id', $salle);            });        }    }    public function scopeEcolage($query, $status){        if($status == 0){            return $query;        }else{            return $query->whereHas('sousetudiants', function($q) use ($status){                if ($status == 'Complet') {                    $q->whereDoesntHave('ecolage', function ($u)  {                        $u->where('payé', 1);                    });                } else {                    $q->whereHas('ecolage', function ($u) {                        $u->where('payé', 0);                    });                }            });        }    }    public function scopeMoisecolage($query, $mois, $status){        if($mois == 0){            return $query;        }else{            return $query->whereHas('sousetudiants', function($q) use ($mois, $status){                    $q->whereHas('ecolage', function ($u) use ($mois, $status) {                        $u->where('mois', $mois)->where('payé',$status =='Complet'?1:0);                    });            });        }    }    public function scopeMentionNote($query, $mention, $niveau){        if($mention == 0){            return $query;        }else{            return $query->whereHas('sousetudiants', function($q) use ($mention, $niveau){                $sub = $niveau == 'prescolaire'?2:1;                    if ($mention === 'Aucune') {                        $q->where('noteTotal', '<', 10/$sub);                    } elseif ($mention === 'passable') {                        $q->where('noteTotal', '<', 12/$sub)->where('noteTotal', '>', 9/$sub);                    } elseif ($mention === 'A-bien') {                        $q->where('noteTotal', '<', 14/$sub)->where('noteTotal', '>', 11/$sub);                    } elseif ($mention === 'Bien') {                        $q->where('noteTotal', '<', 17/$sub)->where('noteTotal', '>', 13/$sub);                    } elseif ($mention === 'Très-bien') {                        $q->where('noteTotal', '<', 19/$sub)->where('noteTotal', '>', 16/$sub);                    } elseif ($mention === 'Honorable') {                        $q->where('noteTotal', '>', 18/$sub);                    }            });        }    }    public function scopeMention($query, $mention){        if($mention == 0){            return $query;        }else{            return $query->whereHas('sousetudiants', function($q) use ($mention){                if ($mention === 'Aucune') {                    $q->where('noteTotal', '<', 10);                } elseif ($mention === 'passable') {                    $q->where('noteTotal', '<', 12)->where('noteTotal', '>', 9);                } elseif ($mention === 'A-bien') {                    $q->where('noteTotal', '<', 14)->where('noteTotal', '>', 11);                } elseif ($mention === 'Bien') {                    $q->where('noteTotal', '<', 17)->where('noteTotal', '>', 13);                } elseif ($mention === 'Très-bien') {                    $q->where('noteTotal', '<', 19)->where('noteTotal', '>', 16);                } elseif ($mention === 'Honorable') {                    $q->where('noteTotal', '>', 18);                }            });        }    }    public function scopeIsGenre($query, $sexe){        return $query->where('sexe', $sexe);    }public function scopeInactif($query){        return $query->where('quit', 1)->orWhere('fired', 1);}    public function scopeQuitorfired($query, $quitorfired){        if($quitorfired == 'Quittés'){            return $query->where('quit', 1);        }elseif($quitorfired == 'Renvoyés'){            return $query->where('fired', 1);        }else{            return $query;        }    }    public function scopeIsNotQuitAndNotFired($query){        return $query->where('quit', 0)->where('fired', 0);    }}